scwin.f_resultPopEd = function (strCd, strNm, rtnList) {
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      return;
    }
    strCd.setValue(rtnList[0]);
    strNm.setValue(rtnList[1]);
  } else {
    strCd.setValue("");
    strNm.setValue("");
  }
};
scwin.f_userToExcel = async function (gr_evid, gridName) {
  let objGrd = $p.getComponentById(gr_evid);
  let objDs = $p.getComponentById(objGrd.getDataListId());
  if (objDs.getRowCount() <= 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_009, Array("데이타"));
    return false;
  }
  $c.data.downloadGridViewExcel($p, gr_evid, {
    "fileName": gridName + ".xlsx",
    "sheetName": gridName
  });
};
scwin.f_checkPopEd2 = function (strCd, strNm, flag) {
  strNm.setValue("");
  if (strCd.getValue().trim() != "") {
    scwin.f_SearchPopUp(flag, "T");
  }
};
